BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name WHERE {
  ?elem rdf:type vocab:actor .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?actor ?actorName ?relatedElem ?relatedName ?relType WHERE {
  ?actor rdf:type vocab:actor .
  OPTIONAL { ?actor vocab:NamedElement_name ?actorName }
  ?actor vocab:Element__relationshipOfRelatedElement ?rel .
  ?rel ?relProp ?relatedElem .
  FILTER(?relProp IN (vocab:Dependency_client, vocab:Dependency_supplier, vocab:Include_addition, vocab:Include_includingCase))
  OPTIONAL { ?relatedElem vocab:NamedElement_name ?relatedName }
  BIND(?relProp AS ?relType)
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?usecase ?usecaseName ?actor ?actorName WHERE {
  ?usecase rdf:type vocab:usecase .
  OPTIONAL { ?usecase vocab:NamedElement_name ?usecaseName }
  FILTER(CONTAINS(LCASE(STR(?usecaseName)), LCASE("APS")))
  ?usecase vocab:UseCase_include ?include .
  ?include vocab:Include_addition ?actor .
  ?actor rdf:type vocab:actor .
  OPTIONAL { ?actor vocab:NamedElement_name ?actorName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  ?pkg vocab:NamedElement_name "Stakeholders" .
  ?pkg vocab:Element_ownedElement+ ?elem .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  OPTIONAL { ?elem rdf:type ?type }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name ?owner WHERE {
  VALUES ?elem {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::Mission::Stakeholders::APS%20User>
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::Mission::Stakeholders::APS%20Operator>
  }
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  OPTIONAL { ?elem rdf:type ?type }
  OPTIONAL { ?elem vocab:Element_owner ?ownerName . ?ownerName vocab:NamedElement_name ?owner }
}

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?name ?type WHERE {
  VALUES ?elem {
    <http://api.koneksys.com/cameo/TMT/actor/_TMT_RecycleBin::Need%2520for%2520Lock-Out%2520method::APS%2520Technician>
    <http://api.koneksys.com/cameo/TMT/actor/_TMT_RecycleBin::Need%2520for%2520Lock-Out%2520method::APS%2520Researcher>
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::Mission::Stakeholders::APS%20User>
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::Mission::Stakeholders::APS%20Operator>
  }
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  OPTIONAL { ?elem rdf:type ?type }
}
